\\ Design is not just what it looks like. Design is how it works. — Steve Jobs

// Define the system parameters
const system = {
    isConfigured: true,
    status: "Graduated"
};

// Log the status dynamically to the console
if (system.isConfigured) {
    console.log(`System Successfully Configured: ${system.status}`);
}

